// Updated Announcements.tsx component with proper class names
import React from 'react';
import './new.css';
import { useCMS } from '../../contexts/CMSContext';

interface AnnouncementsProps {
  featuredOnly?: boolean;
}

const Announcements: React.FC<AnnouncementsProps> = ({ featuredOnly = false }) => {
  const { displayData } = useCMS();
  const { newsContent, programsContent: pc } = displayData.pages.home;

  // Helper to extract first image from HTML body if no explicit thumbnail exists
  const extractFirstImage = (body: string) => {
    if (!body) return null;
    const imgMatch = body.match(/src=["']([^"']+\.(?:jpg|jpeg|png|gif|webp|bmp))["']/i);
    let imageUrl = imgMatch ? imgMatch[1] : null;

    if (imageUrl) {
      imageUrl = imageUrl.replace(
        /http:\/\/bodephatquoc\.org\/wp-content\/uploads\//g, 
        'https://ik.imagekit.io/dloitl7fd8/wp-content/uploads/'
      );
    }
    return imageUrl;
  };

  const announcements = (newsContent.items || []).map((item: any) => ({
    ...item,
    image: item.image || extractFirstImage(item.body)
  }));
  const featuredAnnouncement = announcements.find(item => item.isFeatured) || announcements[0];
  const regularAnnouncements = announcements.filter(item => !item.isFeatured).slice(0, 3);

  if (!announcements || announcements.length === 0) return null;

  return (
    <section className="announcements-section">
      <div className="announcements-container">
        {/* Two-column layout */}
        <div className="announcements-grid">
          {/* Left column - Featured announcement */}
          <div className="announcements-featured">
            {featuredAnnouncement.link && featuredAnnouncement.link !== "#" ? (
              <a href={featuredAnnouncement.link} className="featured-link-wrapper">
                <div className="featured-image">
                  {featuredAnnouncement.image ? (
                    <img
                      src={featuredAnnouncement.image}
                      alt={featuredAnnouncement.title}
                      className="featured-img"
                      onError={(e) => (e.currentTarget.style.display = 'none')}
                    />
                  ) : (
                    <div className="image-placeholder">
                      <div className="placeholder-content">
                        <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                          <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                          <circle cx="8.5" cy="8.5" r="1.5"></circle>
                          <polyline points="21 15 16 10 5 21"></polyline>
                        </svg>
                        <span>Hình ảnh minh họa</span>
                      </div>
                    </div>
                  )}
                </div>
              </a>
            ) : (
              <div className="featured-image">
                {featuredAnnouncement.image ? (
                  <img
                    src={featuredAnnouncement.image}
                    alt={featuredAnnouncement.title}
                    className="featured-img"
                    onError={(e) => (e.currentTarget.style.display = 'none')}
                  />
                ) : (
                  <div className="image-placeholder">
                    <div className="placeholder-content">
                      <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                        <rect x="3" y="3" width="18" height="18" rx="2" ry="2"></rect>
                        <circle cx="8.5" cy="8.5" r="1.5"></circle>
                        <polyline points="21 15 16 10 5 21"></polyline>
                      </svg>
                      <span>Hình ảnh minh họa</span>
                    </div>
                  </div>
                )}
              </div>
            )}

           
          </div>

          {/* Right column - Announcements list */}
          <div className="announcements-list">
            <div className="list-header">
              <h2 className="section-title">{newsContent.sectionTitle}</h2>
              <div className="title-underline"></div>
            </div>

            <div className="announcements-items">
              {regularAnnouncements.map((item) => {
                const hasValidLink = item.link && item.link !== "#";
                return (
                  <div className="announcement-item" key={item.id}>
                    {hasValidLink ? (
                      <a href={item.link} className="announcement-item-link">
                        <div className="announcement-thumb">
                          {item.image ? (
                            <img
                              src={item.image}
                              alt={item.title}
                              className="thumb-img"
                              onError={(e) => (e.currentTarget.style.display = 'none')}
                            />
                          ) : (
                            <div className="thumbnail-placeholder">
                              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                                <rect x="3" y="3" width="18" height="18" rx="1" ry="1"></rect>
                                <circle cx="8.5" cy="8.5" r="1.5"></circle>
                                <polyline points="21 15 16 10 5 21"></polyline>
                              </svg>
                            </div>
                          )}
                        </div>

                        <div className="announcement-text">
                          <h4>{item.title}</h4>
                          <p>{item.subtitle}</p>
                        </div>
                      </a>
                    ) : (
                      <>
                        <div className="announcement-thumb">
                          {item.image ? (
                            <img
                              src={item.image}
                              alt={item.title}
                              className="thumb-img"
                              onError={(e) => (e.currentTarget.style.display = 'none')}
                            />
                          ) : (
                            <div className="thumbnail-placeholder">
                              <svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1">
                                <rect x="3" y="3" width="18" height="18" rx="1" ry="1"></rect>
                                <circle cx="8.5" cy="8.5" r="1.5"></circle>
                                <polyline points="21 15 16 10 5 21"></polyline>
                              </svg>
                            </div>
                          )}
                        </div>

                        <div className="announcement-text">
                          <h4>{item.title}</h4>
                          <p>{item.subtitle}</p>
                        </div>
                      </>
                    )}
                  </div>
                );
              })}
            </div>

            {/* View all link */}
            <div className="view-all-container">
              <a href="/news" className="view-all-link">
                Xem tất cả bản tin
                <svg className="view-all-arrow" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  <path d="M5 12h14M12 5l7 7-7 7" />
                </svg>
              </a>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Announcements;